array.string:
export PATH="$HOME/.local/bin:/usr/local/bin:/opt/homebrew/bin:$PATH";
cd /Users/tm/Projects/Claude/ResearchMan;
LOG=$HOME/Library/Logs/researchman-auto.log;
node scripts/run-if-due.mjs --daily-at 10 >> $LOG 2>&1 || exit 0;
# Technology側(techresearch)と同時発火した際のgit競合を防ぐ排他ロック（最大30分待ち）
LOCK=/tmp/researchman-git.lock; waited=0;
while ! mkdir $LOCK 2>/dev/null; do sleep 30; waited=$((waited+30)); [ $waited -ge 1800 ] && { echo "ロック取得タイムアウト: $(date)" >> $LOG; exit 0; }; done;
trap "rmdir $LOCK 2>/dev/null" EXIT;
echo "===== Run start: $(date) =====" >> $LOG;
if ! node scripts/auto-research-cc.mjs >> $LOG 2>&1; then
  echo "収集エラー終了: $(date)" >> $LOG;
  node scripts/run-if-due.mjs --mark >> $LOG 2>&1;
  node scripts/notify-line.mjs --result error >> $LOG 2>&1;
  exit 0;
fi;
node scripts/self-heal-thumbnails.mjs >> $LOG 2>&1 || echo "self-heal失敗（続行）: $(date)" >> $LOG;
# tech配下はTechnologyパイプラインの管轄なので除外（クラッシュ残骸の混入防止）
git add -- data/cases.json public/thumbnails ":(exclude)public/thumbnails/tech" >> $LOG 2>&1;
if git diff --cached --quiet; then
  echo "変更なし（新規事例なし）: $(date)" >> $LOG;
  node scripts/notify-line.mjs >> $LOG 2>&1;
else
  git commit -m "Auto research: $(date '+%Y-%m-%d')" >> $LOG 2>&1;
  if git push >> $LOG 2>&1; then
    if node scripts/verify-deploy.mjs >> $LOG 2>&1; then
      echo "反映まで確認OK: $(date)" >> $LOG;
      node scripts/send-mail.mjs >> $LOG 2>&1;
      node scripts/notify-line.mjs >> $LOG 2>&1;
    else
      echo "push成功だが反映未確認（時間切れ）: $(date)" >> $LOG;
      node scripts/notify-line.mjs --result unverified >> $LOG 2>&1;
    fi;
  else
    echo "push失敗（pre-push監査で中止の可能性）。コミットはローカル残存。要手動対応: $(date)" >> $LOG;
    node scripts/notify-line.mjs --result pushfail >> $LOG 2>&1;
  fi;
fi;
echo "Completed: $(date)" >> $LOG
